#include <stdio.h>
#include <inttypes.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, X, Y;
        scanf("%lld %lld %lld", &N, &X, &Y);
        if (X * Y >= N) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

